INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('police-b20a8cf8-moex-00454', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '有關「警察遴選第三人蒐集資料辦法」遴選第三人秘密蒐集資料之規定，下列敘述何者正確？', '["該辦法之法源依據為「刑事訴訟法」", "警方為防止個人名譽受危害，亦得遴選第三人秘密蒐集資料", "警方認為第三人之陳述有保全之必要，無須第三人同意，得逕予錄音留存", "遴選期間不得逾1年，認有繼續蒐集必要，每次延長期間不得逾1年，至多延長2次"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "4e3afb2db42f", "answer_pdf_sha1": "235894bbae73", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00455', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '司法警察通知犯罪嫌疑人到場接受詢問之規定，下列敘述何者正確？①司法警察應先進行調查，', '["通知書應記載犯罪嫌疑人之年齡，其年齡係以 周年計算", "通知書之送達，以郵務送達方式為原則", "通知書送達對象為公司負責人時，以送 達其住、居所為原則  ⑤通知書送達對象為少年時，不得為公示送達", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "4e3afb2db42f", "answer_pdf_sha1": "235894bbae73", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 5, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00456', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '偵辦組織犯罪防制條例案件，運用證人保護法實施證人保護事宜，下列敘述何者正確？', '["證人因到場作證致生命、身體、自由、名譽或財產遭受危害之虞，而有保護必要者，得聲請保護", "司法警察如認證人有受保護必要，得先採取必要之保護措施，並於5日內將所採保護措施陳報 檢察官或法院", "偵查中有密切利害關係之人因證人到場作證，而有受保護之必要者，司法警察亦得向檢察官聲 請核發證人保護書", "採取身分保密之保護措施，製作筆錄證人之真實姓名及身分資料應以代號為之，筆錄由詢問員 警代為簽名，並另製作代號及真實姓名對照表，連同詢問錄音（錄影）資料以密封套密封附卷"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "4e3afb2db42f", "answer_pdf_sha1": "235894bbae73", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00457', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '有關司法警察詢問犯罪嫌疑人之規定，下列敘述何者正確？', '["詢問犯罪嫌疑人時應自告知罪名時起，全程連續錄音或錄影", "遇有急迫情形時，司法警察得不經犯罪嫌疑人同意逕行夜間詢問", "有事實上之原因不能為之並全程錄音或錄影，須經嫌疑人同意並記明筆錄，始得進行單警詢問", "製作詢問筆錄，應將詢問過程所有內容逐字加以記錄"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "4e3afb2db42f", "answer_pdf_sha1": "235894bbae73", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00458', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '警方辦理詐欺案件，依「存款帳戶及其疑似不法或顯屬異常交易管理辦法」辦理疑涉不法銀行帳 戶警示，下列敘述何者正確？', '["警示帳戶之開戶人所開立之其他存款帳戶，為衍生管制帳戶，歸類為第2類警示帳戶", "如屬重大緊急案件，警察機關得以電話、傳真等方式先行通知，並應於通知後5個營業日內補 辦公文書資料送達銀行，逾期未補辦者，銀行應直接逕行解除警示帳戶", "警示帳戶之警示期限自通報時起算，逾1年自動失其效力；但有繼續警示之必要者，原通報機 關應於期限屆滿前再行通報之，通報延長以1次及1年為限", "存款帳戶之款項若已遭扣押或禁止處分，再接獲警察機關通報為警示帳戶，該帳戶仍應列為警 示帳戶，但該等款項優先依扣押或禁止處分命令規定辦理"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "4e3afb2db42f", "answer_pdf_sha1": "235894bbae73", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00459', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '偵辦因暴力犯罪導致被害人死亡案件時，應立即陳報分局何單位，依「警察機關關懷協助犯罪被 害人實施計畫」辦理犯罪被害人關懷協助工作？', '["勤務指揮中心", "偵查隊", "行政組", "防治組"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "4e3afb2db42f", "answer_pdf_sha1": "235894bbae73", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00460', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '警方接獲報案稱一男子在路旁砍殺路人，即刻派員到達案發現場，見男子手持沾血尖刀逃入附近', '["進入該民宅將男子逮捕", "逮捕後，搜索男子隨身背包", "逮 捕後，發現該男子停放在犯罪現場附近之機車，逕行打開行李箱搜索", "逮捕後，將該男子由民 宅帶回至犯罪現場確認犯行  ⑤逮捕後，請目擊者立即單一指認並製作指認筆錄"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "4e3afb2db42f", "answer_pdf_sha1": "235894bbae73", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00461', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '目擊者指認之正確性受到諸多因素所影響，下列何者屬於學者Wells（1978）所分類之「系統變 數」（systemvariable）？', '["警方實施指認排列之指導語", "目擊時間之長短", "嫌疑人有無遮掩", "目擊者在目擊時是否飲酒"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "4e3afb2db42f", "answer_pdf_sha1": "235894bbae73", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00462', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '有關提審規定，下列敘述何者正確？', '["得請求提審之受逮捕、拘禁人民，僅限於本國人（含雙重國籍者），不包含外國人", "目擊逮捕、拘禁過程之路人，亦得代受逮捕、拘禁之人請求提審", "逮捕、拘禁之機關收受提審票，24小時內應將被逮捕、拘禁人解交，時間計算應扣除刑事訴訟 法第93條之1第1項法定障礙事由時間", "因犯罪嫌疑而受司法警察機關逮捕者，始有提審法之適用"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "4e3afb2db42f", "answer_pdf_sha1": "235894bbae73", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00463', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', 'M化車可用來進行手機定位，運用M化車偵辦刑案，下列敘述何者正確？', '["運用M化車定位手機位置，必須輸入目標手機之門號", "M化車所欲定位之標的手機無須開機，仍可進行定位", "M化車可截取向其註冊之手機序號（IMEI）及國際標準識別碼（IMSI）", "M化車係依連線訊號強弱並結合GPS判定目標手機位置"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "4e3afb2db42f", "answer_pdf_sha1": "235894bbae73", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL)
